command.text:
        /* <flatten type="Javascript"> */
var f = this, d1 = f.getItemValue('ngay_ct1'), d2 = f.getItemValue('ngay_ct2'), q1 = f.getItemValue('so_luong1'), q2 = f.getItemValue('so_luong2'), v = f._language == 'v', e;
if (q1 && q2 && q1 > q2) {
  f._errorObject = f.getItem('so_luong2');
  e = (v ? 'Trường <span class="Highlight">Số lượng từ</span> phải nhỏ hơn hoặc bằng <span class="Highlight">Số lượng đến</span>.' : '<span class="Highlight">Quantity from</span> must be less than <span class="Highlight">Quantity to</span>.');
  f._checked = false;
}
if (f._checked && d1 > d2) {
  f._errorObject = f.getItem('ngay_ct2');
  e = (v ? 'Trường <span class="Highlight">Ngày bắt đầu hiệu lực</span> phải nhỏ hơn hoặc bằng <span class="Highlight">Ngày kết thúc hiệu lực</span>.' : '<span class="Highlight">Effective from</span> must be less than <span class="Highlight">Effective to</span>.');
  f._checked = false;
}
if (!f._checked) $message.show(e, String.format('$find(\'{0}\')._errorObject.focus()', f.get_id()));
/* </flatten> */

script.text:
      /* <flatten type="Javascript"> */
function active$FormPriceQuotation(f) {
  f.add_onResponseComplete(on$FormPriceQuotation$ResponseComplete);
  set$Voucher$DefaultValue(f);
}
function scatter$FormPriceQuotation(f) {
  set$Voucher$DefaultValue(f);
  set$Multi$UOM(f);
}
function close$FormPriceQuotation(f) {try {f.remove_onResponseComplete(on$FormPriceQuotation$ResponseComplete)} catch (ex) {}}
function onChange$Voucher$Item(o) {
  var f = o.parentForm;
  f.request('Item', 'Item', ['ma_vt'], o);
}
function onChange$VoucherDetail$UOM(o) {
  var f = o.parentForm;
  f.request('CheckMultiUOM', 'CheckMultiUOM', ['ma_vt', 'dvt'], o);
}
function on$FormPriceQuotation$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Item':
      var v = result[2].Value;
      f.setItemControlBehavior('dvt', result[0].Value, result[1].Value, true);
      f.setItemValue('nhieu_dvt', v);
      set$Multi$UOM(f);
      if (v == 1) f.setReferenceKeyFilter('dvt');
      break;
    case 'CheckMultiUOM':
      var v = result[0].Value;
      f.setItemValue('nhieu_dvt', v);
      f.setItemValue('he_so1', result[1].Value);
      set$Multi$UOM(f);
      if (v == 1) f.setReferenceKeyFilter('dvt');
      break;
    case 'Checking':
      break;
    default:
      break;
  }
}
function set$Voucher$DefaultValue(f) {
  var d = new Date();
  if (f._action == "New"){
    f.setItemValue('ngay_ct', d);
    f.setItemValue('ngay_ct1', d);
    f.request('Item', 'Item', ['ma_vt']);
  }
  else if (f._action == "Edit")
    f.request('CheckMultiUOM', 'CheckMultiUOM', ['ma_vt', 'dvt']);
}
function set$Multi$UOM(f) {
  var v = f.getItemValue('nhieu_dvt'), o = f.getItem('dvt');
  $common.setVisible(o.a, v);
  f._setReadOnly(o, !v);
}
/* </flatten> */
